import type { EventEmitter } from 'events';

type ProcessorFunction = ({
	userContext,
	events,
	done,
}: {
	userContext: { vars: Record<string, unknown> };
	events: EventEmitter;
	done: () => void;
}) => void;

export interface Color {
	name: string;
	id: number;
}

export interface Link {
	name: string;
	path: string;
}

export interface Price {
	algorithm: string;
	quantity: number;
	price: string;
}

export interface Product {
	product_id: number;
	decoration_method: string;
	features: string;
	general_comments: string;
	manufacturer: string;
	minimum_quantity: number;
	name: string;
	rating_count: number;
	rating_score: string;
	sizes: string[];
	status: 'active' | 'inactive' | 'deprecated';
	style_type: 'apparel' | 'headwear' | 'bags' | 'accessories';
	product_type: 'Unisex' | 'Mens' | 'Womens' | 'Youth';
	style_card_image_url: string;
	broad_category_names: string[];
	sub_category_names: string[];
	turn_time: number;
	rush_turn_time: number;
	default_unit_prices: Price[];
	link: Link;
	colors: Color[];
	objectID: string;
}

export const generateName: ProcessorFunction = ({ userContext, done }) => {
	const names = [
		'John',
		'Mary',
		'Robert',
		'Patricia',
		'Michael',
		'Jennifer',
		'William',
		'Linda',
		'David',
		'Elizabeth',
		'Richard',
		'Barbara',
		'Joseph',
		'Susan',
		'Thomas',
		'Jessica',
	];
	userContext.vars['name'] = randomChoice({ arr: names });
	done();
};

export const randomThrowError: ProcessorFunction = ({ userContext, done }) => {
	userContext.vars['throwError'] = Math.random() < 0.1;
	done();
};

export const generateProductArray: ProcessorFunction = ({ userContext, done }) => {
	const products: Product[] = [];

	for (let i = 0; i < 30; i++) {
		const productId = 999_600 + Math.floor(Math.random() * 100);

		products.push({
			product_id: productId,
			decoration_method: randomChoice({
				arr: ['embroidery', 'screen printing', 'digital printing', 'heat transfer'],
			}),
			features: generateFeaturesList(),
			general_comments:
				'Classic Carhartt style meets Carhartt durability in this coat which features cotton duck fabric for a tough exterior and a soft sherpa lining for warmth and added coziness.',
			manufacturer: randomChoice({
				arr: ['Sanmar', 'Gildan', 'Hanes', 'Nike', 'Adidas', 'Carhartt'],
			}),
			minimum_quantity: Math.floor(Math.random() * 10) + 1,
			name: `${randomChoice({ arr: ['Carhartt', 'Nike', 'Adidas'] })} ${randomChoice({
				arr: ['Tall', 'Short', 'Regular'],
			})} ${randomChoice({ arr: ['Washed Duck', 'Cotton', 'Polyester'] })} ${randomChoice({
				arr: ['Sherpa-Lined Coat', 'T-Shirt', 'Hoodie'],
			})}`,
			rating_count: Math.floor(Math.random() * 100),
			rating_score: (Math.random() * 5).toFixed(1),
			sizes: generateRandomSubset({
				arr: ['XS', 'S', 'M', 'L', 'XL', 'XXL', 'XXXL', 'LT', 'XLT', 'XXLT', 'XXXLT'],
				count: Math.floor(Math.random() * 5) + 1,
			}),
			status: randomChoice({ arr: ['active', 'inactive', 'deprecated'] }),
			style_type: randomChoice({ arr: ['apparel', 'headwear', 'bags', 'accessories'] }),
			product_type: randomChoice({ arr: ['Unisex', 'Mens', 'Womens', 'Youth'] }),
			style_card_image_url: `https://mms-images.staging.customink.com/mms/images/catalog/${randomString({ length: 32 })}/styles/${productId}/catalog_detail_image_medium.jpg`,
			broad_category_names: generateRandomSubset({
				arr: [
					'Workwear & Uniforms',
					'Business & Occupations',
					'Featured Brands',
					'Embroidery',
					'Jackets',
					'T-shirts',
					'Sweatshirts & Hoodies',
				],
				count: Math.floor(Math.random() * 5) + 1,
			}),
			sub_category_names: generateRandomSubset({
				arr: [
					'Construction',
					'Home Services',
					'Contractors & Landscapers',
					'Carhartt',
					'Outerwear',
					'Work Jackets',
					'All Workwear & Uniforms',
					'Tall Jackets',
					'All Jackets',
					'Workwear',
					'All Embroidery',
				],
				count: Math.floor(Math.random() * 5) + 1,
			}),
			turn_time: Math.floor(Math.random() * 20) + 5,
			rush_turn_time: Math.floor(Math.random() * 10) + 1,
			default_unit_prices: generatePrices(),
			link: {
				name: `Product #${productId}`,
				path: `/products/workwear-uniforms/work-jackets/product-${productId}`,
			},
			colors: generateRandomSubset({
				arr: [
					{ name: 'Black', id: 100 + Math.floor(Math.random() * 900) },
					{ name: 'White', id: 100 + Math.floor(Math.random() * 900) },
					{ name: 'Red', id: 100 + Math.floor(Math.random() * 900) },
					{ name: 'Blue', id: 100 + Math.floor(Math.random() * 900) },
					{ name: 'Green', id: 100 + Math.floor(Math.random() * 900) },
					{ name: 'Carhartt Brown', id: 100 + Math.floor(Math.random() * 900) },
				],
				count: Math.floor(Math.random() * 3) + 1,
			}),
			objectID: productId.toString(),
		});
	}

	userContext.vars['products'] = products;
	done();
};

/** Helpers */
function randomChoice<T>({ arr }: { arr: T[] }): T {
	return arr[Math.floor(Math.random() * arr.length)] as T;
}

function generateRandomSubset<T>({ arr, count }: { arr: T[]; count: number }): T[] {
	const shuffled = [...arr].sort(() => 0.5 - Math.random());
	return shuffled.slice(0, count);
}

function randomString({ length }: { length: number }): string {
	const characters = 'abcdefghijklmnopqrstuvwxyz0123456789';
	let result = '';
	for (let i = 0; i < length; i++) {
		result += characters.charAt(Math.floor(Math.random() * characters.length));
	}
	return result;
}

function generateFeaturesList(): string {
	const features = [
		'Quilted nylon lined sleeves for easy on-and-off',
		'Pleated bi-swing back for additional range of motion',
		'Longer length for more coverage',
		'Left chest pocket with zipper closure',
		'Two interior pockets',
		'Two large, sherpa-lined hand-warming front pockets',
		'Interior rib knit storm cuffs help keep out the cold',
		'Carhartt-strong, triple-stitched main seams for added durability',
		'Carhartt label sewn on left pocket',
		'Water-resistant fabric',
		'Machine washable',
	];
	return generateRandomSubset({ arr: features, count: Math.floor(Math.random() * 5) + 3 })
		.map((f) => `* ${f}`)
		.join('\r\n');
}

function generatePrices(): Price[] {
	const algorithms = ['default-2022-03-24', 'plus_5-2024-04-30', 'minus_5-2024-04-30'];
	const quantities = [15, 20, 25, 50, 100, 500];
	const prices: Price[] = [];

	for (const algorithm of algorithms) {
		if (Math.random() > 0.3) {
			for (const quantity of quantities) {
				if (Math.random() > 0.4) {
					const basePrice = 200 + Math.random() * 50;
					const adjustedPrice = basePrice * (1 - quantity / 1000);
					prices.push({
						algorithm,
						quantity,
						price: adjustedPrice.toFixed(2),
					});
				}
			}
		}
	}

	return prices;
}
